<?php
namespace App\Domain\GameHome;
final class GameHomeCardDestinationType{const ROUTE='route';const ACTIVE_CHARACTER_OVERVIEW='active_character_overview';const CHARACTER_SELECTOR='character_selector';const EXTERNAL_URL='external_url';public static function all(){return[self::ROUTE,self::ACTIVE_CHARACTER_OVERVIEW,self::CHARACTER_SELECTOR,self::EXTERNAL_URL];}public static function labels(){return[self::ROUTE=>'Ruta del juego',self::ACTIVE_CHARACTER_OVERVIEW=>'Overview del personaje activo',self::CHARACTER_SELECTOR=>'Selector de personajes',self::EXTERNAL_URL=>'URL externa'];}public static function supports($value){return in_array($value,self::all(),true);}public static function requiresValue($value){return in_array($value,[self::ROUTE,self::EXTERNAL_URL],true);}private function __construct(){}}
